    const MOD = 1000003;

    if (n === 1) {
        return m % MOD;
    }

    // dp[i][j] will store the number of ways to color the first i squares
    // such that the i-th square is colored with color j
    const dp: number[][] = Array.from({ length: n + 1 }, () => Array(m).fill(0));

    // Initialize the first square
